<?php // api/blog.php header('Content-Type: application/json'); $allowedOriginsEnv = getenv('BLOG_ALLOWED_ORIGINS')?: 'https://www.broadsafeservices.com.au,https://broadsafeservices.com.au'; $allowedOrigins = array_filter(array_map('trim', explode(',', $allowedOriginsEnv))); if (!empty($_SERVER['HTTP_ORIGIN']) && in_array($_SERVER['HTTP_ORIGIN'], $allowedOrigins, true)) { header('Access-Control-Allow-Origin: '. $_SERVER['HTTP_ORIGIN']); header('Vary: Origin'); } header('Access-Control-Allow-Methods: GET, POST, PUT, DELETE, OPTIONS'); header('Access-Control-Allow-Headers: Content-Type, X-API-KEY, Authorization'); if ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') { http_response_code(204); exit; } function getConfigValue($key) { if (defined($key) && constant($key)!== '') { return constant($key); } $value = getenv($key); return ($value!== false && $value!== '')? $value: null; } function requireApiKey { $apiKey = getConfigValue('BLOG_API_KEY'); if (!$apiKey) { http_response_code(500); echo json_encode(['success' => false, 'message' => 'API key not configured.']); exit; } $providedKey = $_SERVER['HTTP_X_API_KEY']?? ''; $authHeader = $_SERVER['HTTP_AUTHORIZATION']?? ''; if (stripos($authHeader, 'Bearer ') === 0) { $providedKey = trim(substr($authHeader, 7)); } if (!$providedKey ||!hash_equals($apiKey, $providedKey)) { http_response_code(401); echo json_encode(['success' => false, 'message' => 'Unauthorized']); exit; } } require_once '../database.php'; $database = new Database(); $conn = $database->getConnection(); require_once '../blog-setup.php'; ensureBlogTables($conn); // Get all published posts if ($_SERVER['REQUEST_METHOD'] === 'GET' &&!isset($_GET['id'])) { $limit = isset($_GET['limit'])? (int)$_GET['limit']: 10; $page = isset($_GET['page'])? (int)$_GET['page']: 1; $offset = ($page - 1) * $limit; $category = isset($_GET['category'])? $_GET['category']: null; $search = isset($_GET['search'])? $_GET['search']: null; $sql = "SELECT p.*, c.name as category_name FROM blog_po