' => $featuredImage, ':is_featured' => $isFeatured, ':read_time' => $readTime, ':meta_description' => $metaDescription, ':meta_keywords' => $metaKeywords ]); $postId = $conn->lastInsertId; updateBlogCategoryCounts($conn); echo json_encode([ 'success' => true, 'message' => 'Post created successfully', 'post_id' => $postId ]); } catch (PDOException $e) { echo json_encode(['success' => false, 'message' => $e->getMessage]); } } // Update existing post if ($_SERVER['REQUEST_METHOD'] === 'PUT') { $data = json_decode(file_get_contents('php://input'), true); $data = is_array($data)? $data: []; $id = isset($_GET['id'])? (int)$_GET['id']: (int)($data['id']?? 0); if ($id <= 0) { http_response_code(400); echo json_encode(['success' => false, 'message' => 'Post id is required.']); exit; } $allowedFields = [ 'title', 'slug', 'excerpt', 'content', 'category', 'author_name', 'author_initials', 'author_title', 'featured_image', 'is_featured', 'read_time', 'meta_description', 'meta_keywords', 'publish_date', 'status' ]; $updates = []; $params = [':id' => $id]; foreach ($allowedFields as $field) { if (array_key_exists($field, $data)) { $updates[] = "$field =:$field"; $params[":$field"] = $data[$field]; } } if (empty($updates)) { http_response_code(400); echo json_encode(['success' => false, 'message' => 'No fields provided to update.']); exit; } $sql = "UPDATE blog_posts SET ". implode(', ', $updates). ", updated_at = NOW WHERE id =:id"; $stmt = $conn->prepare($sql); $stmt->execute($params); if ($stmt->rowCount === 0) { $checkStmt = $conn->prepare("SELECT id FROM blog_posts WHERE id =:id"); $checkStmt->execute([':id' => $id]); if (!$checkStmt->fetch) { http_response_code(404); echo json_encode(['success' => false, 'message' => 'Post not found.']); exit; } } updateBlogCategoryCounts($conn); echo json_encode(['success' => true, 'message' => 'Post updated successfully.']); } // Delete post if ($_SERVER['REQUEST_METHOD'] === 'DELETE') { $id = isset($_GET['id'])? (int)$_GET['id']: 0; if ($